async function loadVcScript() {
    try {
        const vcSettings = window.VC_SETTINGS || window.vc_settings || undefined;
        const response = await fetch(`https://chat.visitor.chat/api/v2/webSettings/embed?identifier=${vcSettings?.id || location.host}`);
        const { legacy } = await response.json();

        const scriptUrl = legacy
            ? 'https://cdn.visitor.chat/embed-legacy.min.js'
            : 'https://cdn.visitor.chat/embed-new.min.js';

        const script = document.createElement('script');
        script.src = scriptUrl;
        script.onload = () => console.log('VC script loaded');
        script.onerror = () => console.error('Failed to load VC script');
        document.head.appendChild(script);
    } catch (error) {
        console.error('Failed to fetch config:', error);
        // Fallback to legacy build.
        const script = document.createElement('script');
        script.src = 'https://cdn.visitor.chat/embed-legacy.min.js';
        document.head.appendChild(script);
    }
}

loadVcScript();
